def get_inkilap_referans(kazanim_kodu: str) -> str:
    """Kazanım koduna göre referans içerik döndürür."""
    if kazanim_kodu in INKILAP_REFERANS:
        ref = INKILAP_REFERANS[kazanim_kodu]
        return f"[{ref['unite']}] {ref['baslik']}\n{ref['icerik']}"
    return ""


def get_inkilap_referans_by_topic(konu: str) -> str:
    """Konu metnine göre İLGİLİ TÜM referans içerikleri döndürür (çoklu eşleşme)."""
    konu_lower = konu.lower()
    scored = []

    for kod, ref in INKILAP_REFERANS.items():
        score = 0
        baslik_lower = ref["baslik"].lower()
        icerik_lower = ref["icerik"].lower()

        # Başlıktaki kelimeleri kontrol et
        for word in konu_lower.split():
            if len(word) > 3:
                if word in baslik_lower:
                    score += 10
                if word in icerik_lower:
                    score += 1

        if score >= 3:
            scored.append((score, kod, ref))

    if not scored:
        return ""

    # Skora göre sırala, en yüksekten en düşüğe
    scored.sort(key=lambda x: x[0], reverse=True)

    # En iyi eşleşmenin skorunun %40'ından fazla olan TÜM eşleşmeleri al (en fazla 5)
    best_score = scored[0][0]
    threshold = best_score * 0.4
    results = []
    for score, kod, ref in scored[:5]:
        if score >= threshold:
            results.append(f"### {kod}: {ref['baslik']}\n{ref['icerik']}")

    return "\n\n".join(results)


def get_all_referans_for_unite(unite_no: int) -> str:
    """Ünite numarasına göre tüm kazanımların referansını döndürür."""
    results = []
    for kod, ref in INKILAP_REFERANS.items():
        if f"İTA.8.{unite_no}." in kod:
            results.append(f"### {kod}: {ref['baslik']}\n{ref['icerik']}")
    return "\n\n".join(results)
